2|import "./styles/tokens.css"; // active theme — generated by scaffold (see THEMES.md)
3|import "./styles/base.css";
4|import "./styles/animations.css";
5|
6|import { useCallback } from "react";
7|import { AutoStartGate } from "./components/AutoStartGate";
8|import { AutoToggle } from "./components/AutoToggle";
9|import { ProgressBar } from "./components/ProgressBar";
10|import { Stage } from "./components/Stage";
11|import { useAudioPlayer } from "./hooks/useAudioPlayer";
12|import { useAutoMode } from "./hooks/useAutoMode";
13|import { useStepper } from "./hooks/useStepper";
14|import { CHAPTERS } from "./registry/chapters";
15|
16|/**
17| * Estimate spoken duration of a Chinese narration string. Native pace
18| * ≈ 4 char/s → 250ms per char. Used as Auto-mode fallback ONLY when the
19| * audio file is missing / fails / the narration is empty. When audio plays
20| * normally, this value is unused — auto-advance fires on `audio.ended`.
21| */
22|function estimateMs(text: string): number {
23|  if (!text) return 1500;
24|  return Math.max(1500, text.length * 250);
25|}
26|
27|export default function App() {
28|  const stepper = useStepper(CHAPTERS);
29|  const ch = CHAPTERS[stepper.cursor.chapter]!;
30|  const Cmp = ch.Component;
31|  const stepText = ch.narrations[stepper.cursor.step] ?? "";
32|
33|  const { mode, cycleMode, autoStarted, setAutoStarted } = useAutoMode();
34|
35|  // Audio path follows the convention: /audio/<chapter-id>/<step+1>.mp3
36|  // (1-indexed file names match what `extract-narrations.ts` outputs.)
37|  // Empty narration → no audio src, Auto mode falls back to estimate.
38|  const audioSrc =
39|    mode === "manual" || stepText === ""
40|      ? null
41|      : `${import.meta.env.BASE_URL}audio/${ch.id}/${stepper.cursor.step + 1}.mp3`;
42|
43|  const onAutoAdvance = useCallback(() => stepper.next(), [stepper]);
44|
45|  useAudioPlayer({
46|    src: audioSrc,
47|    mode,
48|    trailMs: 200,
49|    estimateFallbackMs: estimateMs(stepText),
50|    onAutoAdvance,
51|    autoStarted,
52|  });
53|
54|  return (
55|    <>
56|      <Stage onAdvance={stepper.next}>
57|        <div key={ch.id} className="scene">
58|          <Cmp step={stepper.cursor.step} />
59|        </div>
60|      </Stage>
61|      <ProgressBar
62|        chapters={CHAPTERS}
63|        cursor={stepper.cursor}
64|        onJumpChapter={stepper.jumpToChapter}
65|      />
66|      <AutoToggle mode={mode} onCycle={cycleMode} />
67|      <AutoStartGate
68|        visible={mode === "auto" && !autoStarted}
69|        onStart={() => setAutoStarted(true)}
70|      />
71|    </>
72|  );
73|}
