{"content": "1|import { useCallback, useEffect, useMemo, useState } from "react";
2|import type { ChapterDef } from "../registry/types";
3|
4|/**
5| * Bump this when chapter step counts / structure change so old persisted
6| * cursors don't land mid-removed-step.
7| */
8|const STORAGE_KEY = "presentation-cursor-v4";
9|
10|export type Cursor = { chapter: number; step: number };
11|
12|export interface StepperState {
13|  cursor: Cursor;
14|  totalChapters: number;
15|  chapterTotalSteps: number;
16|  globalIndex: number;
17|  totalGlobal: number;
18|  next(): void;
19|  prev(): void;
20|  jumpToChapter(idx: number, step?: number): void;
21|  jumpToGlobal(globalIdx: number): void;
22|}
23|
24|const clamp = (n: number, lo: number, hi: number) =>
25|  Math.max(lo, Math.min(hi, n));
26|
27|/**
28| * Clamp a (possibly stale) cursor to the current chapter list. Persisted
29| * cursors can outlive structural changes — fewer chapters, fewer steps,
30| * a different scaffolded project sharing the same dev-server origin — so
31| * we always re-validate before handing one to React.
32| */
33|function sanitize(cursor: Cursor, chapters: ChapterDef[]): Cursor {
34|  if (chapters.length === 0) return { chapter: 0, step: 0 };
35|  const chapter = clamp(cursor.chapter | 0, 0, chapters.length - 1);
36|  const stepCount = chapters[chapter]!.narrations.length;
37|  const step = clamp(cursor.step | 0, 0, Math.max(0, stepCount - 1));
38|  return { chapter, step };
39|}
40|
41|export function useStepper(chapters: ChapterDef[]): StepperState {
42|  const [cursor, setCursor] = useState<Cursor>(() => {
43|    const fallback = { chapter: 0, step: 0 };
44|    if (typeof window === "undefined") return fallback;
45|    try {
46|      const raw = window.localStorage.getItem(STORAGE_KEY);
47|      if (raw) return sanitize(JSON.parse(raw), chapters);
48|    } catch {
49|      /* ignore */
50|    }
51|    return fallback;
52|  });
53|
54|  // Re-sanitize if the chapter list shape changes after mount (e.g. HMR
55|  // updates `chapters.ts`) — keeps a stale persisted cursor from leaking
56|  // into a render where it's now out of range.
57|  useEffect(() => {
58|    setCursor((cur) => {
59|      const next = sanitize(cur, chapters);
60|      return next.chapter === cur.chapter && next.step === cur.step
61|        ? cur
62|        : next;
63|    });
64|  }, [chapters]);
65|
66|  useEffect(() => {
67|    try {
68|      window.localStorage.setItem(STORAGE_KEY, JSON.stringify(cursor));
69|    } catch {
70|      /* ignore */
71|    }
72|  }, [cursor]);
73|
74|  const offsets = useMemo(() => {
75|    const arr: number[] = [];
76|    let acc = 0;
77|    for (const c of chapters) {
78|      arr.push(acc);
79|      acc += c.narrations.length;
80|    }
81|    return arr;
82|  }, [chapters]);
83|  const totalGlobal = useMemo(
84|    () => chapters.reduce((s, c) => s + c.narrations.length, 0),
85|    [chapters],
86|  );
87|  const globalIndex = (offsets[cursor.chapter] ?? 0) + cursor.step;
88|
89|  const next = useCallback(() => {
90|    setCursor((cur) => {
91|      const c = chapters[cur.chapter]!;
92|      if (cur.step < c.narrations.length - 1)
93|        return { ...cur, step: cur.step + 1 };
94|      if (cur.chapter < chapters.length - 1)
95|        return { chapter: cur.chapter + 1, step: 0 };
96|      return cur;
97|    });
98|  }, [chapters]);
99|
100|  const prev = useCallback(() => {
101|    setCursor((cur) => {
102|      if (cur.step > 0) return { ...cur, step: cur.step - 1 };
103|      if (cur.chapter > 0) {
104|        const p = chapters[cur.chapter - 1]!;
105|        return { chapter: cur.chapter - 1, step: p.narrations.length - 1 };
106|      }
107|      return cur;
108|    });
109|  }, [chapters]);
110|
111|  const jumpToChapter = useCallback(
112|    (idx: number, step = 0) => {
113|      const ch = clamp(idx, 0, chapters.length - 1);
114|      const c = chapters[ch]!;
115|      setCursor({
116|        chapter: ch,
117|        step: clamp(step, 0, c.narrations.length - 1),
118|      });
119|    },
120|    [chapters],
121|  );
122|
123|  const jumpToGlobal = useCallback(
124|    (g: number) => {
125|      const target = clamp(g, 0, totalGlobal - 1);
126|      let acc = 0;
127|      for (let i = 0; i < chapters.length; i++) {
128|        const t = chapters[i]!.narrations.length;
129|        if (target < acc + t) {
130|          setCursor({ chapter: i, step: target - acc });
131|          return;
132|        }
133|        acc += t;
134|      }
135|    },
136|    [chapters, totalGlobal],
137|  );
138|
139|  useEffect(() => {
140|    const onKey = (e: KeyboardEvent) => {
141|      if (e.target instanceof HTMLInputElement) return;
142|      if (e.key === "ArrowRight" || e.key === " ") {
143|        e.preventDefault();
144|        next();
145|      } else if (e.key === "ArrowLeft" || e.key === "Backspace") {
146|        e.preventDefault();
147|        prev();
148|      } else if (e.key === "Home") {
149|        jumpToChapter(0, 0);
150|      } else if (e.key === "End") {
151|        const last = chapters.length - 1;
152|        jumpToChapter(last, chapters[last]!.narrations.length - 1);
153|      } else if (e.key >= "1" && e.key <= "9") {
154|        const n = Number(e.key) - 1;
155|        if (n < chapters.length) jumpToChapter(n, 0);
156|      }
157|    };
158|    window.addEventListener("keydown", onKey);
159|    return () => window.removeEventListener("keydown", onKey);
160|  }, [next, prev, jumpToChapter, chapters]);
161|
162|  const ch = chapters[cursor.chapter]!;
163|  return {
164|    cursor,
165|    totalChapters: chapters.length,
166|    chapterTotalSteps: ch.narrations.length,
167|    globalIndex,
168|    totalGlobal,
169|    next,
170|    prev,
171|    jumpToChapter,
172|    jumpToGlobal,
173|  };
174|}
