{"content":"import { ChapterStepProps } from "../../registry/types";
import "./Hook.css";

const features = [
  { icon: "🔍", title: "联网搜索", desc: "结合实时信息回答" },
  { icon: "📚", title: "本地知识库", desc: "上传文档，AI 基于你资料回答" },
  { icon: "🎨", title: "AI 绘图", desc: "DALL-E / Stable Diffusion 直接出图" },
  { icon: "🔄", title: "多模型切换", desc: "GPT / Claude / DeepSeek / Gemini 随意切" },
];

export default function Hook({ step }: ChapterStepProps) {
  return (
    <div className="hk-stage">
      {/* Step 0: Hook — "还在用 ChatGPT？试试 LobeChat" */}
      {step === 0 && (
        <div className="hk-hero">
          <div className="hk-hero-line hk-hero-q">
            <span className="hk-hero-text">还在用 ChatGPT 网页版？</span>
          </div>
          <div className="hk-hero-line hk-hero-a">
            <span className="hk-hero-arrow">→</span>
            <span className="hk-hero-text hk-hero-strong">试试自己搭 LobeChat</span>
          </div>
          <div className="hk-sub">体验和功能都吊打官方</div>
        </div>
      )}

      {/* Step 1: Feature cards */}
      {step === 1 && (
        <div className="hk-features">
          <div className="hk-features-label">LobeChat 到底强在哪</div>
          <div className="hk-features-grid">
            {features.map((f, i) => (
              <div
                key={i}
                className="hk-card"
                style={{ animationDelay: `${i * 0.15}s` }}
              >
                <div className="hk-card-icon">{f.icon}</div>
                <div className="hk-card-title">{f.title}</div>
                <div className="hk-card-desc">{f.desc}</div>
                <div className="hk-card-bar" />
              </div>
            ))}
          </div>
          <div className="hk-features-footnote">
            GitHub Star 近 10 万 · 完全开源 · 可自托管
          </div>
        </div>
      )}
    </div>
  );
}
