.hk-stage {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-display-en), var(--font-display-cn), sans-serif;
  color: var(--text);
}

/* ─── Step 0: Hero ─── */

.hk-hero {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.8em;
}

.hk-hero-line {
  opacity: 0;
  animation: hkFadeSlideIn 0.5s ease-out forwards;
}

.hk-hero-q {
  animation-delay: 0s;
}

.hk-hero-a {
  animation-delay: 1.2s;
}

.hk-hero-text {
  font-size: 72px;
  font-weight: 600;
  letter-spacing: -0.02em;
}

.hk-hero-strong {
  color: var(--accent);
  font-weight: 800;
}

.hk-hero-arrow {
  font-size: 56px;
  margin-right: 0.2em;
  color: var(--accent);
  font-weight: 300;
}

.hk-sub {
  margin-top: 0.5em;
  font-size: 24px;
  color: var(--text-mute);
  font-weight: 400;
  opacity: 0;
  animation: hkFadeSlideIn 0.5s ease-out forwards;
  animation-delay: 2s;
}

/* ─── Step 1: Feature cards ─── */

.hk-features {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2.5em;
}

.hk-features-label {
  font-size: 32px;
  font-weight: 700;
  color: var(--text);
  letter-spacing: -0.01em;
  opacity: 0;
  animation: hkFadeSlideIn 0.4s ease-out forwards;
}

.hk-features-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 1.2em;
  width: 100%;
  max-width: 900px;
}

.hk-card {
  background: var(--surface-2);
  border-radius: var(--r-card);
  padding: 1.8em 1.2em;
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.6em;
  position: relative;
  overflow: hidden;
  opacity: 0;
  transform: translateY(20px);
  animation: hkCardIn 0.45s ease-out forwards;
}

.hk-card-icon {
  font-size: 36px;
  line-height: 1;
}

.hk-card-title {
  font-size: 20px;
  font-weight: 700;
  color: var(--text);
}

.hk-card-desc {
  font-size: 13px;
  color: var(--text-mute);
  line-height: 1.4;
}

.hk-card-bar {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: var(--accent);
  transform: scaleX(0);
  transform-origin: left;
  animation: hkBarGrow 0.5s ease-out forwards;
  animation-delay: 0.6s;
}

.hk-features-footnote {
  font-size: 14px;
  color: var(--text-faint);
  letter-spacing: 0.03em;
  font-weight: 400;
  opacity: 0;
  animation: hkFadeIn 0.5s ease-out forwards;
  animation-delay: 1.2s;
}

/* ─── Keyframes ─── */

@keyframes hkFadeSlideIn {
  from {
    opacity: 0;
    transform: translateY(12px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes hkFadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes hkCardIn {
  from {
    opacity: 0;
    transform: translateY(24px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes hkBarGrow {
  from { transform: scaleX(0); }
  to { transform: scaleX(1); }
}
